class Solution {
public:
    int kIncreasing(vector<int>& arr, int k) {
        int n = arr.size();
        vector<int> dp(n, 0);
        for (int i = 0; i < n; i++) {
            int prev = INT_MIN;
            for (int j = i - k; j < i; j++) {
                if (j >= 0) {
                    prev = max(prev, arr[j]);
                }
            }
            int min_val = 0;
            for (int j = i - k; j < i; j++) {
                if (j >= 0 && arr[j] <= arr[i]) {
                    min_val = max(min_val, dp[j]);
                }
            }
            dp[i] = min_val + 1;
        }
        int max_val = 0;
        for (int i = 0; i < n; i++) {
            max_val = max(max_val, dp[i]);
        }
        return n - max_val;
    }
};

